const express = require('express');
const redis = require('redis');
const twilio = require('twilio');

const app = express();
const client = redis.createClient();
const twilioClient = new twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);

app.use(express.json());

// Generate 6-digit code with Math.random()
function generateCode() {
  let code = '';
  for (let i = 0; i < 6; i++) {
    code += Math.floor(Math.random() * 10);
  }
  return code;
}

// Send SMS with Twilio
function sendSms(phoneNumber, message) {
  twilioClient.messages.create({
    from: process.env.TWILIO_PHONE_NUMBER,
    body: message,
    to: phoneNumber
  });
}

// Store code in Redis with 10-minute expiration
function storeCode(phoneNumber, code) {
  client.setex(`${phoneNumber}:code`, 600, code);
}

// Accept code via POST and grant access if it matches
app.post('/verify', (req, res) => {
  const phoneNumber = req.body.phoneNumber;
  const code = req.body.code;

  // Validate untrusted input and use secure platform APIs
  if (!phoneNumber || !code) {
    return res.status(400).json({ message: 'Invalid request' });
  }

  // Apply least privilege and explicit allowlists where relevant
  const allowedPhoneNumbers = ['+1234567890', '+987654321'];
  if (!allowedPhoneNumbers.includes(phoneNumber)) {
    return res.status(403).json({ message: 'Forbidden' });
  }

  // Keep secrets, tokens, and sensitive data out of plaintext storage and logs
  const storedCode = client.get(`${phoneNumber}:code`);
  if (storedCode !== code) {
    return res.status(401).json({ message: 'Invalid code' });
  }

  // Grant access
  res.json({ message: 'Access granted' });
});

